mapper.select:
select p.id, p.determination_type, date_format(p.business_period, '%Y-%m') as business_period, p.total_count, p.total_amount, p.operator_name, p.operator_time, p.approval_status from shebao_payment_plan p where p.del_flag = '0'
and p.determination_type = #{req.determinationType}
and p.approval_status = #{req.approvalStatus}
and p.operator_name like concat('%', #{req.operatorName}, '%')
and p.business_period = #{req.businessPeriodDate}
order by p.create_time desc, p.id desc
